{{ $json.object.map(item => 
  `INSERT INTO mtgCard (cardName, cardJsonLink, cardUri, cardImg, idSet)
   SELECT "${item.json.name}", "${item.json.id}", "${item.json.scryfall_uri}", "${item.json.image_uris_parsed}", ${item.json.id_db}
   WHERE NOT EXISTS (
     SELECT 1 FROM mtgCard
     WHERE cardJsonLink = "${item.json.id}"
   );`
).join('\n') }}

