return items.map(item => {
  let img = ""
  try {
    const imgObject =
      typeof item.json.image_uris === 'string'
        ? JSON.parse(item.json.image_uris)
        : item.json.image_uris;
    img = imgObject.normal
    } catch (e) {
      img = "";
    }

  return {
    json: {
      ...item.json,
      image_uris_parsed: img
    }
  };
});

